import { useEffect, useState } from "react";
import Note from "./components/note";
import Notification from "./components/notification";
import Footer from "./components/footer";
import { createNote, getAllNotes, updateNote } from "./services/notes";

export default function App() {
  const [notes, setNotes] = useState([]);
  const [newNote, setNewNote] = useState("a new note...");
  const [showAll, setShowAll] = useState(true);
  const notesToShow = showAll ? notes : notes.filter((note) => note.important);
  const [errorMessage, setErrorMessage] = useState(null);

  useEffect(() => {
    getAllNotes().then((notes) => {
      setNotes(notes);
    });
  }, []);

  function addNote(e) {
    e.preventDefault();
    const newNoteObject = {
      content: newNote,
      date: new Date().toISOString(),
      important: Math.random() < 0.5,
    };

    createNote(newNoteObject).then((createdNote) => {
      setNotes(notes.concat(createdNote));
      setNewNote("");
    });
  }

  function handleToggleImportance(id) {
    const note = notes.find((note) => note.id === id);
    const updatedNoteObject = { ...note, important: !note.important };

    updateNote(id, updatedNoteObject)
      .then((updatedNote) => {
        setNotes(notes.map((note) => (note.id !== id ? note : updatedNote)));
      })
      .catch(() => {
        setErrorMessage(
          `Note '${note.content}' was already deleted from server`
        );
        setTimeout(() => setErrorMessage(null), 5000);
        setNotes(notes.filter((note) => note.id !== id));
      });
  }

  return (
    <div>
      <h1>Notes</h1>
      <Notification message={errorMessage} />
      <div>
        <button onClick={() => setShowAll(!showAll)}>
          show {showAll ? "important" : "all"}
        </button>
      </div>
      <ul>
        {notesToShow.map((note) => (
          <Note
            key={note.id}
            details={note}
            onToggleImportance={() => handleToggleImportance(note.id)}
          />
        ))}
      </ul>
      <form onSubmit={addNote}>
        <input value={newNote} onChange={(e) => setNewNote(e.target.value)} />
        <button type="submit">save</button>
      </form>
      <Footer />
    </div>
  );
}
